using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<long long> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];

    long long max_product = nums[0];
    long long min_product = nums[0];
    long long result = nums[0];
    for(int i = 1; i < n; i++){
        long long temp = max_product;
        max_product = max(nums[i], max(max_product * nums[i], min_product * nums[i]));
        min_product = min(nums[i], min(temp * nums[i], min_product * nums[i]));
        result = max(result, max_product);
    }
    cout << result << endl;
    return 0;
}
